+        {
+            return self.ppr_from_source_parallel(graph, source, alpha, num_walks);
+        }
+
+        #[cfg(not(feature = "parallel"))]
+        {
+            let mut rng = self.make_rng();
+            let mut counts = vec![0u64; graph.rows];
