+            for _ in 0..num_walks {
+                let endpoint = Self::single_walk(graph, source, alpha, &mut rng);
+                counts[endpoint] += 1;
+            }
+
+            let inv = 1.0 / num_walks as f64;
+            let mut result: Vec<(usize, f64)> = counts
+                .into_iter()
+                .enumerate()
+                .filter(|(_, c)| *c > 0)
+                .map(|(v, c)| (v, c as f64 * inv))
+                .collect();
