+// ---------------------------------------------------------------------------
+// SolverEngine
+// ---------------------------------------------------------------------------
+
+impl SolverEngine for HybridRandomWalkSolver {
+    fn solve(
+        &self,
+        matrix: &CsrMatrix<f64>,
+        rhs: &[f64],
+        budget: &ComputeBudget,
+    ) -> Result<SolverResult, SolverError> {
+        let n = matrix.rows;
+        if n != matrix.cols {
+            return Err(SolverError::InvalidInput(
