+        #[cfg(feature = "parallel")]
+        let counts = {
+            use rayon::prelude::*;
+
+            let num_chunks = rayon::current_num_threads().max(1);
+            let walks_per_chunk = walks / num_chunks;
+            let remainder = walks % num_chunks;
+
+            (0..num_chunks)
+                .into_par_iter()
+                .map(|chunk_idx| {
