+            let mut rng = self.make_rng();
+            let mut counts = vec![0.0f64; n];
+            for _ in 0..walks {
+                if start_time.elapsed() > budget.max_time {
+                    return Err(SolverError::BudgetExhausted {
+                        reason: "wall-clock time limit exceeded".into(),
+                        elapsed: start_time.elapsed(),
+                    });
+                }
