+                let r: f64 = rng.gen();
+                let start_node = cdf.partition_point(|&c| c < r).min(n - 1);
+                let endpoint =
+                    Self::single_walk(matrix, start_node, self.alpha, &mut rng);
+                counts[endpoint] += 1.0;
+            }
