+    );
+
+    // NaN in RHS should be rejected.
+    let rhs = vec![1.0f32, f32::NAN, 3.0];
+    let err_rhs = validate_rhs(&rhs, 3).unwrap_err();
+    assert!(
+        matches!(err_rhs, ValidationError::NonFiniteValue(_)),
+        "expected NonFiniteValue for NaN in RHS, got {:?}",
